 punctuation&#34;&gt;.&lt;/span&gt;id&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;imageButton6&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        button_play&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;setOnClickListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;View&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;OnClickListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token annotation punctuation&#34;&gt;@Override&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;onClick&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;View&lt;/span&gt; v&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 判断是否没在播放音乐&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;!&lt;/span&gt;mediaPlayer&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;isPlaying&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    mediaPlayer&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;start&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 播放音乐&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        button_stop&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;setOnClickListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;View&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;OnClickListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token annotation punctuation&#34;&gt;@Override&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;onClick&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;View&lt;/span&gt; v&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 判断是否在播放音乐&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;mediaPlayer&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;isPlaying&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    mediaPlayer&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;pause&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 暂停音乐&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h4 id=&#34;简单的操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#简单的操作系统&#34;&gt;#&lt;/a&gt; 简单的操作系统&lt;/h4&gt;
&lt;h5 id=&#34;汇编代码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#汇编代码&#34;&gt;#&lt;/a&gt; 汇编代码&lt;/h5&gt;
&lt;pre&gt;&lt;code class=&#34;language-asm&#34;&gt;; hello-os
; TAB=4

		ORG		0x7c00			; 指明程序装载地址

; 标准FAT12格式软盘专用的代码 Stand FAT12 format floppy code

		JMP		entry
		DB		0x90
		DB		&amp;quot;HELLOIPL&amp;quot;		; 启动扇区名称（8字节）
		DW		512				; 每个扇区（sector）大小（必须512字节）
		DB		1				; 簇（cluster）大小（必须为1个扇区）
		DW		1				; FAT起始位置（一般为第一个扇区）
		DB		2				; FAT个数（必须为2）
		DW		224				; 根目录大小（一般为224项）
		DW		2880			; 该磁盘大小（必须为2880扇区1440*1024/512）
		DB		0xf0			; 磁盘类型（必须为0xf0）
		DW		9				; FAT的长度（必??9扇区）
		DW		18				; 一个磁道（track）有几个扇区（必须为18）
		DW		2				; 磁头数（必??2）
		DD		0				; 不使用分区，必须是0
		DD		2880			; 重写一次磁盘大小
		DB		0,0,0x29		; 意义不明（固定）
		DD		0xffffffff		; （可能是）卷标号码
		DB		&amp;quot;HELLO-OS   &amp;quot;	; 磁盘的名称（必须为11字?，不足填空格）
		DB		&amp;quot;FAT12   &amp;quot;		; 磁盘格式名称（必??8字?，不足填空格）
		RESB	18				; 先空出18字节

; 程序主体

entry:
		MOV		AX,0			; 初始化寄存器
		MOV		SS,AX
		MOV		SP,0x7c00
		MOV		DS,AX
		MOV		ES,AX

		MOV		SI,msg
putloop:
		MOV		AL,[SI]
		ADD		SI,1			; 给SI加1
		CMP		AL,0
		JE		fin
		MOV		AH,0x0e			; 显示一个文字
		MOV		BX,15			; 指定字符颜色
		INT		0x10			; 调用显卡BIOS
		JMP		putloop
fin:
		HLT						; 让CPU停止，等待指令
		JMP		fin				; 无限循环

msg:
		DB		0x0a, 0x0a		; 换行两次
		DB		&amp;quot;hello, world&amp;quot;
		DB		0x0a			; 换行
		DB      &amp;quot;hello MYOS,K1T000&amp;quot;
		DB		0x0a			; 换行
		DB		0

		RESB	0x7dfe-$		; 填写0x00直到0x001fe

		DB		0x55, 0xaa

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;利用工具构建&lt;br /&gt;
&lt;strong&gt; makefile&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;1. &lt;strong&gt;Makefile 的功能&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Makefile&lt;/code&gt;  是一种用于自动化构建过程的脚本文件，通常与  &lt;code&gt;make&lt;/code&gt;  工具一起使用。在开发中，它定义了如何编译和链接代码，如何生成目标文件，如何处理依赖关系等。通过  &lt;code&gt;make&lt;/code&gt;  命令，开发人员可以根据  &lt;code&gt;Makefile&lt;/code&gt;  中的指令自动执行任务，比如编译源代码、创建可执行文件、生成镜像文件等。&lt;/p&gt;
&lt;p&gt;具体来说， &lt;code&gt;Makefile&lt;/code&gt;  包含：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;目标（target）：如  &lt;code&gt;helloos.img&lt;/code&gt; 、 &lt;code&gt;helloos.bin&lt;/code&gt;  等生成的文件。&lt;/li&gt;
&lt;li&gt;规则（rule）：定义如何生成目标文件的步骤。&lt;/li&gt;
&lt;li&gt;依赖关系（dependency）：指定哪些文件或目标是当前目标的依赖。&lt;/li&gt;
&lt;li&gt;命令（command）：用于生成目标文件的具体操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;采用汇编&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#采用汇编&#34;&gt;#&lt;/a&gt; 采用汇编&lt;/h5&gt;
&lt;p&gt;1. &lt;strong&gt;为什么用汇编语言写操作系统？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;写操作系统时，选择使用汇编语言通常有以下几个原因：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(1) 操作系统对硬件的直接控制&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;操作系统，尤其是引导程序、内核的早期部分，需要直接控制硬件资源（如 CPU、内存、硬盘等）。汇编语言提供了极低级别的控制，使你能够精确地操作硬件，比如设置中断向量、控制内存映射等。&lt;/p&gt;
&lt;p&gt;在操作系统启动的早期阶段（引导加载程序），需要与硬件打交道，这时 C 语言的抽象就不再合适，汇编提供的直接访问硬件的能力是必要的。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(2) 性能和效率&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;汇编语言是一种低级语言，通常比高级语言（如 C 语言）更高效。对于内核的某些关键部分，使用汇编可以实现非常高效的操作，如上下文切换、任务调度等。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(3) 学习和理解底层原理&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;通过汇编语言写操作系统的早期部分，你可以深入了解计算机的底层架构，包括 CPU 寄存器、栈操作、中断机制等。这对理解操作系统的工作原理非常有帮助。&lt;/p&gt;
&lt;p&gt;2. &lt;strong&gt;为什么不直接用 C 语言写操作系统？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;虽然 C 语言在编写操作系统时非常流行，但它并不是完全适合于操作系统所有部分的语言。操作系统的早期阶段（如引导加载程序）确实需要使用汇编语言。以下是一些原因，解释为什么 C 语言通常不会在操作系统的整个开发过程中取代汇编语言：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(1) 操作系统的启动过程&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;在操作系统启动的初期阶段，CPU 和硬件设备的控制非常直接。你必须配置中断、设置段寄存器、初始化内存等，这些操作 C 语言通常做不到。C 语言对硬件的抽象非常强，它需要操作系统提供的运行时环境来支持，而在操作系统的引导加载过程中（也就是  &lt;code&gt;bootloader&lt;/code&gt;  阶段），这些环境尚未建立。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(2) C 语言依赖于运行时库&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;C 语言虽然非常接近硬件，但它依赖于操作系统的运行时库（例如标准库、系统调用等），这些库在操作系统本身没有完成之前无法使用。操作系统内核的开发必须考虑到这些库在编译时没有定义的情况，因此，直接使用 C 语言的执行环境并不适合操作系统的最初开发。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(3) 操作系统设计中的低级任务&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;有些操作系统的设计任务需要处理直接与硬件相关的低级任务。例如，操作系统的中断处理、设备驱动、任务调度等，需要非常精确的控制和高效的代码。这些任务用汇编语言编写时更为简单和高效，而在 C 语言中，编译器的优化有时会使代码变得不够高效，特别是与硬件交互时。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;(4) 更好的移植性和可维护性&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;尽管操作系统开发时可能会用汇编语言，但现代操作系统的核心部分通常还是会用 C 语言开发。因为 C 语言具备较好的移植性、可维护性和易读性，尤其是相对于汇编语言。汇编语言的代码是与硬件架构紧密耦合的，因此难以移植，而 C 语言能够在不同的硬件平台上进行相对容易的移植。&lt;/p&gt;
&lt;h5 id=&#34;关于-make-的使用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关于-make-的使用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;关于  &lt;code&gt;Make&lt;/code&gt;  的使用&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;Make&lt;/code&gt;  是一个自动化工具，主要用于自动化编译和构建过程。它可以让你通过一个  &lt;code&gt;Makefile&lt;/code&gt;  文件定义如何从源代码生成目标文件（如  &lt;code&gt;.o&lt;/code&gt;  文件、可执行文件等）。让我们来看一下如何使用  &lt;code&gt;Make&lt;/code&gt;  来编译一个汇编语言编写的操作系统。&lt;/p&gt;
&lt;h5 id=&#34;基本的-makefile-结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本的-makefile-结构&#34;&gt;#&lt;/a&gt; &lt;strong&gt;基本的  &lt;code&gt;Makefile&lt;/code&gt;  结构&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;一个简单的  &lt;code&gt;Makefile&lt;/code&gt;  包含以下几个基本部分：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;目标（target）&lt;/strong&gt;：你希望生成的文件，比如  &lt;code&gt;.o&lt;/code&gt;  文件、最终的可执行文件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;依赖（dependency）&lt;/strong&gt;：生成目标所需要的源文件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;规则（rule）&lt;/strong&gt;：从依赖生成目标的命令。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;假设你有一个简单的操作系统源码，包含以下文件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;boot.asm&lt;/code&gt; ：引导程序（使用汇编语言编写）&lt;/li&gt;
&lt;li&gt;&lt;code&gt;kernel.asm&lt;/code&gt; ：操作系统内核（使用汇编语言编写）&lt;/li&gt;
&lt;li&gt;&lt;code&gt;link.ld&lt;/code&gt; ：链接脚本，用于将生成的目标文件链接成最终的可执行镜像&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt; &lt;code&gt;make&lt;/code&gt; &lt;/strong&gt; 工具不仅仅用于编译操作系统项目，它实际上是一个非常通用的自动化构建工具，广泛应用于各种编程项目中，无论是 C 语言、C++、汇编语言，还是其他语言的项目。它的核心功能是通过  &lt;code&gt;Makefile&lt;/code&gt;  自动化地管理源代码的编译、链接等过程，使得项目的构建变得更加高效和可重复。&lt;/p&gt;
&lt;h5 id=&#34;make-的应用场景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#make-的应用场景&#34;&gt;#&lt;/a&gt; &lt;strong&gt; &lt;code&gt;make&lt;/code&gt;  的应用场景&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;make&lt;/code&gt;  工具可以用于编译许多类型的项目，常见的包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;C/C++ 项目&lt;/strong&gt;：这是  &lt;code&gt;make&lt;/code&gt;  最常见的应用场景，尤其是在大型项目中，可以帮助管理多个源文件的编译与链接。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Python 项目&lt;/strong&gt;：虽然 Python 本身不需要编译，但  &lt;code&gt;make&lt;/code&gt;  可以用于自动化测试、打包、清理等任务。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Java 项目&lt;/strong&gt;：尽管 Maven 或 Gradle 是更常用的构建工具，但  &lt;code&gt;make&lt;/code&gt;  也可以用于编译 Java 源文件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;汇编语言项目&lt;/strong&gt;：正如你在操作系统开发中看到的， &lt;code&gt;make&lt;/code&gt;  也可以用来自动化汇编语言文件的编译过程。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;其他脚本语言&lt;/strong&gt;：对于 Bash 脚本、Ruby 脚本等， &lt;code&gt;make&lt;/code&gt;  可以用来执行特定任务，如运行测试、部署应用等。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;编译&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编译&#34;&gt;#&lt;/a&gt; 编译&lt;/h5&gt;
&lt;p&gt;make file 或者直接 nask.exe  helloos.nas  helloos.img&lt;/p&gt;
&lt;p&gt;2、虚拟机启动操作系统&lt;/p&gt;
&lt;p&gt;Step1：启动 VMware，创建一个新的虚拟机 MyOS（注意加上软盘驱动器）；&lt;/p&gt;
&lt;p&gt;Step2：设置从软盘镜像文章中启动系统，文件为刚做好的 helloos.img&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;&#34; alt=&#34;&#34; /&gt; &lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105145924.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
Step3：启动该虚拟机&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105145942.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;h4 id=&#34;系统调用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统调用&#34;&gt;#&lt;/a&gt; 系统调用&lt;/h4&gt;
&lt;p&gt;Linux 系统中，用户程序可以通过隐式调用或显示调用使用系统调用。&lt;/p&gt;
&lt;p&gt;隐式调用 —— 用户通过封装了系统调用的 API 使用系统调用&lt;/p&gt;
&lt;p&gt;显式调用 —— 使用 syscall () 函数实现调用，int syscall (int number,…)，number 是系统调用号&lt;/p&gt;
&lt;h5 id=&#34;基础&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基础&#34;&gt;#&lt;/a&gt; 基础&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;syscall&lt;/code&gt;  并不仅仅用于获取进程 ID（PID），它是用于直接与操作系统内核交互的一种方式，允许你调用任何支持的系统调用。 &lt;code&gt;syscall&lt;/code&gt;  函数是一个低级接口，通过它你可以直接发起操作系统的系统调用。&lt;/p&gt;
&lt;h3 id=&#34;syscall-的基本用法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#syscall-的基本用法&#34;&gt;#&lt;/a&gt;  &lt;code&gt;syscall&lt;/code&gt;  的基本用法&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;syscall&lt;/code&gt;  函数是一个系统调用接口，允许你通过系统调用号来调用操作系统内核提供的底层功能。它的基本签名通常如下：&lt;/p&gt;
&lt;p&gt;c&lt;/p&gt;
&lt;p&gt;&lt;code&gt;long syscall(long number, ...);&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;number&lt;/code&gt;  是系统调用的编号，也就是操作系统为每个系统调用分配的一个唯一的数字（如  &lt;code&gt;SYS_getpid&lt;/code&gt; 、 &lt;code&gt;SYS_read&lt;/code&gt;  等）。&lt;/li&gt;
&lt;li&gt;后面的  &lt;code&gt;...&lt;/code&gt;  是系统调用的参数，具体取决于你要调用的系统调用。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;syscall-支持的系统调用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#syscall-支持的系统调用&#34;&gt;#&lt;/a&gt;  &lt;code&gt;syscall&lt;/code&gt;  支持的系统调用&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;syscall&lt;/code&gt;  函数是通用的，可以用来调用几乎所有的系统调用，不仅仅是  &lt;code&gt;getpid&lt;/code&gt; 。以下是一些常见的可以通过  &lt;code&gt;syscall&lt;/code&gt;  调用的操作系统系统调用：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;进程管理相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_getpid&lt;/code&gt; ：获取当前进程的 PID（进程 ID）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_fork&lt;/code&gt; ：创建一个新的进程（子进程）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_exit&lt;/code&gt; ：使当前进程退出。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_getppid&lt;/code&gt; ：获取父进程的 PID。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_waitpid&lt;/code&gt; ：等待子进程的状态改变。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;文件操作相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_open&lt;/code&gt; ：打开文件。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_read&lt;/code&gt; ：从文件描述符中读取数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_write&lt;/code&gt; ：向文件描述符写入数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_close&lt;/code&gt; ：关闭文件描述符。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_lseek&lt;/code&gt; ：设置文件指针的位置。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;内存管理相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_brk&lt;/code&gt; ：改变数据段的结束地址。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_mmap&lt;/code&gt; ：内存映射文件或设备到进程的虚拟内存。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_munmap&lt;/code&gt; ：解除内存映射。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;信号和中断相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_kill&lt;/code&gt; ：发送信号给进程。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_signal&lt;/code&gt; ：设置信号处理程序。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;网络操作相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_socket&lt;/code&gt; ：创建一个新的网络套接字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_connect&lt;/code&gt; ：连接到远程主机。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_sendto&lt;/code&gt; ：向指定的地址发送数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_recvfrom&lt;/code&gt; ：从指定的地址接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;时间和日期相关的系统调用&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SYS_time&lt;/code&gt; ：获取系统的当前时间。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SYS_gettimeofday&lt;/code&gt; ：获取当前时间戳。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;隐式调用实际上是指别人已经为你封装好了底层的功能，你不需要手动调用底层的系统调用（如  &lt;code&gt;syscall&lt;/code&gt; ），而是通过更高级的接口来实现相同的功能。这种封装不仅让你在编程时更加方便，也提高了代码的可读性和可维护性。&lt;/p&gt;
&lt;h5 id=&#34;libc&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#libc&#34;&gt;#&lt;/a&gt; libc&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;libc&lt;/code&gt; （C 语言标准库， &lt;code&gt;lib&lt;/code&gt;  是 &amp;quot;library&amp;quot; 的缩写）是一个包含 C 语言标准函数的库。它为开发者提供了许多标准功能，诸如输入输出（I/O）、内存管理、字符串操作、数学函数等。在类 Unix 操作系统中， &lt;code&gt;libc&lt;/code&gt;  通常是一个包含系统调用封装的共享库。&lt;/p&gt;
&lt;h5 id=&#34;实验&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实验&#34;&gt;#&lt;/a&gt; 实验&lt;/h5&gt;
&lt;figure class=&#34;highlight c&#34;&gt;&lt;figcaption data-lang=&#34;c&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;syscall.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;unistd.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;stdio.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;&lt;span class=&#34;token directive-hash&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;token directive keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&amp;lt;sys/types.h&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;viod&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token keyword&#34;&gt;long&lt;/span&gt; ID1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ID2&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	ID1&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;syscall&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SYS_getpid&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;     &lt;span class=&#34;token comment&#34;&gt;/* 显式系统调用 */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token function&#34;&gt;printf&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;“&lt;span class=&#34;token function&#34;&gt;syscall&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SYS_getpid&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;ld\n”&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ID1&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	ID2&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getpid&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;                &lt;span class=&#34;token comment&#34;&gt;/* 使用 libc 封装的隐式系统调用 */&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token function&#34;&gt;printf&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;“&lt;span class=&#34;token function&#34;&gt;getpid&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;ld\n”&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ID2&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; 	&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;[[Ettercap]] 少不了这个 arp 毒化和流量截取的中间人工具。&lt;/p&gt;
&lt;h4 id=&#34;dns欺骗原理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dns欺骗原理&#34;&gt;#&lt;/a&gt; dns 欺骗原理&lt;/h4&gt;
&lt;h5 id=&#34;什么是-dns-欺骗&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#什么是-dns-欺骗&#34;&gt;#&lt;/a&gt; 什么是 DNS 欺骗？&lt;/h5&gt;
&lt;p&gt;&lt;strong&gt;DNS 欺骗（DNS Spoofing）&lt;/strong&gt; 是一种网络攻击技术，攻击者通过修改 DNS 响应，将目标用户的 DNS 查询结果篡改，指向攻击者控制的服务器。DNS 是域名解析服务的缩写，它将用户输入的域名（例如  &lt;code&gt;www.example.com&lt;/code&gt; ）转化为与之对应的 IP 地址（例如  &lt;code&gt;192.168.1.1&lt;/code&gt; ）。如果攻击者能控制 DNS 响应，就能让用户访问到攻击者伪造的服务器，而不是正确的目标服务器。&lt;/p&gt;
&lt;h5 id=&#34;ettercap-和-dns-欺骗-的作用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ettercap-和-dns-欺骗-的作用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;Ettercap&lt;/strong&gt; 和 &lt;strong&gt;DNS 欺骗&lt;/strong&gt; 的作用&lt;/h5&gt;
&lt;p&gt;&lt;strong&gt;Ettercap&lt;/strong&gt; 是一款强大的网络嗅探和中间人攻击工具，它支持多种攻击方式，包括 &lt;strong&gt;ARP 欺骗&lt;/strong&gt;、&lt;strong&gt;DNS 欺骗&lt;/strong&gt;、&lt;strong&gt;流量注入&lt;/strong&gt;等。我们现在关注的是 &lt;strong&gt;DNS 欺骗&lt;/strong&gt;，这是通过以下几个步骤实现的。&lt;/p&gt;
&lt;h5 id=&#34;1-arp-欺骗arp-spoofing&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-arp-欺骗arp-spoofing&#34;&gt;#&lt;/a&gt; 1. &lt;strong&gt;ARP 欺骗（ARP Spoofing）&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;DNS 欺骗本身并不是一个独立的攻击行为，而是通常与 &lt;strong&gt;ARP 欺骗&lt;/strong&gt; 配合使用的。要理解这个过程，我们需要先了解什么是 &lt;strong&gt;ARP（地址解析协议）&lt;/strong&gt;。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;ARP（Address Resolution Protocol）&lt;/strong&gt; 用于在局域网内根据设备的 IP 地址找到其对应的 MAC 地址。&lt;/li&gt;
&lt;li&gt;在局域网中，设备之间的通信是通过 &lt;strong&gt;MAC 地址&lt;/strong&gt; 来标识的，但当你要发送数据时，需要知道目标设备的 &lt;strong&gt;IP 地址&lt;/strong&gt; 和 &lt;strong&gt;MAC 地址&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;ARP 欺骗&lt;/strong&gt; 是通过发送伪造的 ARP 包，告诉网络中的其他设备：&lt;strong&gt;&amp;quot;我是你们要与之通信的目标（例如网关或某台设备），所以你们应该将数据发送到我这里。&amp;quot;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;通过 &lt;strong&gt;ARP 欺骗&lt;/strong&gt;，攻击者可以让流量流经自己的计算机，成为中间人。&lt;/p&gt;
&lt;h5 id=&#34;2-dns-欺骗的实现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-dns-欺骗的实现&#34;&gt;#&lt;/a&gt; 2. &lt;strong&gt;DNS 欺骗的实现&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;一旦使用 ARP 欺骗使得攻击者处于目标与目标网关之间（即中间人位置），接下来的步骤就是 DNS 欺骗。这个步骤的基本流程如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;目标机器通过 &lt;strong&gt;ARP 欺骗&lt;/strong&gt; 将其网络流量重定向到攻击者计算机。&lt;/li&gt;
&lt;li&gt;当目标机器发出 DNS 请求时，攻击者会截获该请求，并返回伪造的 DNS 响应。&lt;/li&gt;
&lt;li&gt;例如，目标机器可能请求解析  &lt;code&gt;www.example.com&lt;/code&gt;  的 IP 地址。攻击者通过 Ettercap 或其他工具返回一个伪造的 IP 地址（比如攻击者自己的 IP 地址）作为 DNS 响应。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;3-ettercap-如何实现-dns-欺骗&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-ettercap-如何实现-dns-欺骗&#34;&gt;#&lt;/a&gt; 3. &lt;strong&gt;Ettercap 如何实现 DNS 欺骗&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;Ettercap 通过嗅探网络流量并劫持 DNS 请求，向目标返回伪造的 DNS 响应来实现 DNS 欺骗。以下是该过程的具体工作方式：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;嗅探和中间人攻击&lt;/strong&gt;：攻击者使用 ARP 欺骗将自己置于目标和目标网关之间，使得所有流量都通过攻击者的计算机。此时，攻击者成为中间人。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;DNS 请求拦截&lt;/strong&gt;：当目标设备发起 DNS 查询时（例如查询  &lt;code&gt;www.example.com&lt;/code&gt; ），这些请求会通过攻击者的机器发送。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;DNS 响应伪造&lt;/strong&gt;：攻击者通过配置 Ettercap 工具，在  &lt;code&gt;etter.dns&lt;/code&gt;  配置文件中指定伪造的 DNS 解析结果（例如将  &lt;code&gt;www.example.com&lt;/code&gt;  指向攻击者的 IP 地址）。然后，Ettercap 将伪造的 DNS 响应发送给目标。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;目标访问攻击者的伪造服务器&lt;/strong&gt;：目标机器收到伪造的 DNS 响应后，会尝试访问被篡改的 IP 地址，通常是攻击者的计算机，从而将受害者引导到攻击者控制的站点或服务器。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;4-ettercap-中-dns-欺骗的配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-ettercap-中-dns-欺骗的配置&#34;&gt;#&lt;/a&gt; 4. &lt;strong&gt;Ettercap 中 DNS 欺骗的配置&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;在 Ettercap 中，你可以通过配置  &lt;code&gt;etter.dns&lt;/code&gt;  文件来指定 DNS 欺骗的行为。这个配置文件包含了伪造的 DNS 记录，比如：&lt;/p&gt;
&lt;p&gt;plaintext&lt;/p&gt;
&lt;p&gt;&lt;code&gt;* A 192.168.197.193   # 将所有域名解析为攻击者的 IP 地址 * PTR 192.168.197.193 # 反向解析，确保所有指向攻击者 IP 的域名都被正确解析&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;通过这种方式，Ettercap 在执行中间人攻击时能够篡改所有 DNS 请求的响应，将目标请求重定向到攻击者指定的服务器（通常是攻击者自己的 IP 地址）。&lt;/p&gt;
&lt;h5 id=&#34;5-实际应用中的攻击效果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-实际应用中的攻击效果&#34;&gt;#&lt;/a&gt; 5. &lt;strong&gt;实际应用中的攻击效果&lt;/strong&gt;&lt;/h5&gt;
&lt;p&gt;DNS 欺骗可以被用来进行多种攻击，包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;钓鱼攻击&lt;/strong&gt;：将目标用户引导到一个伪造的网站（例如伪造银行网站），以获取用户的登录凭据。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;流量窃取&lt;/strong&gt;：通过将目标设备指向一个恶意的 DNS 服务器，攻击者可以窃取用户的流量。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;拒绝服务攻击（DoS）&lt;/strong&gt;：将目标设备的 DNS 查询指向一个不存在的或无法响应的 IP 地址，导致目标无法访问网站&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;应用场景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#应用场景&#34;&gt;#&lt;/a&gt; 应用场景&lt;/h5&gt;
&lt;p&gt;一般来讲 arp 欺骗只能在局域网中使用 ，同时 dns 欺骗不一定只能在局域网中，因为我们还可以拿到路由器的权限之后就可以截获多个网络的 dns 解析请求，从而实现中间人攻击返回 dns 解析响应。&lt;/p&gt;
&lt;h5 id=&#34;正向和反向解析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#正向和反向解析&#34;&gt;#&lt;/a&gt; 正向和反向解析&lt;/h5&gt;
&lt;p&gt;在 DNS 欺骗中，&lt;strong&gt;正向解析&lt;/strong&gt;（Forward Lookup）和 &lt;strong&gt;反向解析&lt;/strong&gt;（Reverse Lookup）都有特定的配置目的，这两种解析方式通过不同的方式影响网络通信的行为。具体来说，在使用 &lt;strong&gt;Ettercap&lt;/strong&gt; 进行 DNS 欺骗时，正向解析和反向解析的配置非常重要，下面我来详细解释这两者的作用和配置原因。&lt;/p&gt;
&lt;h6 id=&#34;1-正向解析forward-lookup&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-正向解析forward-lookup&#34;&gt;#&lt;/a&gt; 1. &lt;strong&gt;正向解析（Forward Lookup）&lt;/strong&gt;&lt;/h6&gt;
&lt;p&gt;正向解析是 DNS 的常规操作，即将 &lt;strong&gt;域名&lt;/strong&gt; 转换为 &lt;strong&gt;IP 地址&lt;/strong&gt;。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;例子&lt;/strong&gt;：当你在浏览器中输入  &lt;code&gt;www.example.com&lt;/code&gt;  时，浏览器会通过 DNS 查询  &lt;code&gt;www.example.com&lt;/code&gt;  对应的 IP 地址。DNS 服务将返回一个 IP 地址（比如  &lt;code&gt;93.184.216.34&lt;/code&gt; ），然后浏览器使用这个 IP 地址与服务器建立连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在 DNS 欺骗中，正向解析的配置通常用于：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;将域名指向攻击者的 IP 地址&lt;/strong&gt;：假设目标要访问的是  &lt;code&gt;www.example.com&lt;/code&gt; ，攻击者可以将该域名的解析结果伪造为攻击者的 IP 地址。这样，当受害者查询  &lt;code&gt;www.example.com&lt;/code&gt;  时，返回的并不是正确的服务器 IP，而是攻击者的服务器或计算机的 IP 地址。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;例如，在 Ettercap 的配置文件  &lt;code&gt;etter.dns&lt;/code&gt;  中，正向解析可能看起来是这样的：&lt;/p&gt;
&lt;p&gt;&lt;code&gt;www.example.com A 192.168.197.193   # 将 www.example.com 解析为攻击者的 IP 地址&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这里  &lt;code&gt;www.example.com&lt;/code&gt;  的 A 记录将指向攻击者的 IP 地址  &lt;code&gt;192.168.197.193&lt;/code&gt; ，这就使得任何访问  &lt;code&gt;www.example.com&lt;/code&gt;  的目标设备都会被重定向到攻击者的机器。&lt;/p&gt;
&lt;h6 id=&#34;2-反向解析reverse-lookup&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-反向解析reverse-lookup&#34;&gt;#&lt;/a&gt; 2. &lt;strong&gt;反向解析（Reverse Lookup）&lt;/strong&gt;&lt;/h6&gt;
&lt;p&gt;反向解析是指将 &lt;strong&gt;IP 地址&lt;/strong&gt; 转换为 &lt;strong&gt;域名&lt;/strong&gt;。这通常是通过 &lt;strong&gt;PTR 记录&lt;/strong&gt;（Pointer Record）实现的。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;例子&lt;/strong&gt;：假设某个网站的服务器 IP 地址是  &lt;code&gt;93.184.216.34&lt;/code&gt; ，你可以进行反向 DNS 查询，获取该 IP 地址对应的域名（比如  &lt;code&gt;example.com&lt;/code&gt; ）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;反向解析在 DNS 欺骗中的作用是，确保当目标设备试图进行反向 DNS 查询时，返回的域名是合理的，避免因域名与 IP 地址不匹配而引起怀疑。&lt;/p&gt;
&lt;h6 id=&#34;3-为什么正向解析和反向解析都要配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-为什么正向解析和反向解析都要配置&#34;&gt;#&lt;/a&gt; 3. &lt;strong&gt;为什么正向解析和反向解析都要配置？&lt;/strong&gt;&lt;/h6&gt;
&lt;p&gt;在进行 DNS 欺骗时，攻击者往往不仅想要将目标用户的请求重定向到攻击者控制的服务器，还希望这些伪造的 DNS 解析结果看起来是可信的。为此，正向解析和反向解析都需要被配置，以达到以下效果&lt;/p&gt;
&lt;p&gt;解析实操配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 反向解析配置&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;100.1&lt;/span&gt;.168.192.in-addr.arpa PTR www.example.com&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;101.1&lt;/span&gt;.168.192.in-addr.arpa PTR ftp.example.com&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 正向解析配置&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;www.example.com A &lt;span class=&#34;token number&#34;&gt;192.168&lt;/span&gt;.1.100&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ftp.example.com A &lt;span class=&#34;token number&#34;&gt;192.168&lt;/span&gt;.1.101&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;实验&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实验&#34;&gt;#&lt;/a&gt; 实验&lt;/h4&gt;
&lt;h5 id=&#34;实验机器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实验机器&#34;&gt;#&lt;/a&gt; 实验机器&lt;/h5&gt;
&lt;p&gt;&lt;strong&gt;操作系统&lt;/strong&gt;：Kali Linux（攻击机）和 Windows/Linux（目标机）在同一局域网内。&lt;br /&gt;
&lt;strong&gt;工具&lt;/strong&gt;：Ettercap、Apache（在 Kali 上运行一个伪造的 Web 服务）。&lt;br /&gt;
&lt;strong&gt;网络配置&lt;/strong&gt;：攻击机与目标机同处一个子网，Kali 具备足够权限（需要 root 权限）。&lt;/p&gt;
&lt;p&gt;其实简单说一下就是，我们保证实验环境我们在一个局域网，同时我们利用操作进行 arp 毒化，使得我们的 kali 充当路由器的功能，之后截取受害者 dns 解析流量，然后解析成我们的 ip，使得他返回我们的攻击 ip。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;钓鱼&lt;/li&gt;
&lt;li&gt;截取流量，捕获局域网内相关流量&lt;/li&gt;
&lt;/ol&gt;
&lt;h5 id=&#34;arp欺骗&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#arp欺骗&#34;&gt;#&lt;/a&gt; arp 欺骗&lt;/h5&gt;
&lt;p&gt;网关 192.168.234.235&lt;br /&gt;
 接下来使用 ettercap 进行 arp 毒化&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ettercap &lt;span class=&#34;token parameter variable&#34;&gt;-G&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;启动&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105202402.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;h5 id=&#34;伪造网关和受害者机器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#伪造网关和受害者机器&#34;&gt;#&lt;/a&gt; . 伪造网关和受害者机器&lt;/h5&gt;
&lt;p&gt;如果你只伪造了网关（比如通过 ARP 中毒将网关的 IP 地址与攻击者的 MAC 地址绑定），这样一来，所有&lt;strong&gt;发往外部网络&lt;/strong&gt;的流量（即目标主机想要访问互联网或其他网络的流量）就会流向你的设备。也就是说：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;目标主机想通过网关访问外部网络时，会把数据包发给你的设备（因为它误认为你的设备是网关）。&lt;/li&gt;
&lt;li&gt;你可以读取、修改这些流量，甚至将它们转发给真实网关，从而完成 Man-in-the-Middle 攻击。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;但是，仅仅伪造网关并不能拦截从目标主机到网关的&lt;strong&gt;反向流量&lt;/strong&gt;，因为：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;网关会将数据包发往目标主机，但网关的 ARP 表中依然会保留目标主机的真实 MAC 地址。&lt;/li&gt;
&lt;li&gt;目标主机并没有修改 ARP 表，它仍然认为网关的 MAC 地址是正常的。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;所以，仅仅伪造网关不会影响目标主机和网关之间的流量反向传输。为了拦截完整的流量，你需要同时伪造目标主机的 ARP 表，让网关也误认为攻击者是目标主机。&lt;/p&gt;
&lt;h5 id=&#34;2-伪造网关和目标主机的-arp-表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-伪造网关和目标主机的-arp-表&#34;&gt;#&lt;/a&gt; 2. &lt;strong&gt;伪造网关和目标主机的 ARP 表&lt;/strong&gt;：&lt;/h5&gt;
&lt;p&gt;为了拦截整个网络流量，攻击者需要同时对&lt;strong&gt;两个方向&lt;/strong&gt;的 ARP 表进行修改：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;目标主机：&lt;/strong&gt; 使目标主机误认为攻击者的 MAC 地址是网关的 MAC 地址。这样，目标主机将会把发往网关的数据包发送到攻击者，而不是实际的网关。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;网关：&lt;/strong&gt; 使网关误认为攻击者的 MAC 地址是目标主机的 MAC 地址。这样，网关将数据包发送给攻击者，而不是目标主机。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这样，&lt;strong&gt;两条数据流都经过攻击者的设备&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;目标主机发往网关的流量会先经过攻击者。&lt;/li&gt;
&lt;li&gt;网关发往目标主机的流量也会经过攻击者。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这种操作实现了&lt;strong&gt;双向拦截&lt;/strong&gt;，保证了流量的完整性。如果你只伪造网关，可能只有目标主机发往外部的流量会经过你，但如果目标主机和网关的反向通信不经过你，攻击的效果就会受到限制。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Kali 设置网络转发：echo 1 &amp;gt; /proc/sys/net/ipv4/ip forward&lt;/strong&gt;&lt;br /&gt;
 因为默认不开启，只有开启了之后才能在不同接口转发流量。一般来讲因为 kali 需要充当路由器所以必须开。&lt;/p&gt;
&lt;h5 id=&#34;设置配置文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#设置配置文件&#34;&gt;#&lt;/a&gt; 设置配置文件&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;vim&lt;/span&gt; /etc/ettercap/etter.dns&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105204243.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 开始 dns 毒化&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105204732.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241105205945.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;可以看到已经启动了&lt;/p&gt;
&lt;p&gt;但是记得删除 解析记录&lt;/p&gt;
&lt;p&gt;Windows 查看 dns 缓存命令：ipconfig /displaydns;&lt;/p&gt;
&lt;p&gt;清理 dns 缓存命令：ipconfig /flushdns&lt;/p&gt;

 &lt;h4 id=&#34;泛洪攻击的类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#泛洪攻击的类型&#34;&gt;#&lt;/a&gt; 泛洪攻击的类型&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;TCP SYN Flood&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者向目标服务器发送大量的 TCP SYN 请求，但不完成握手过程。服务器为每个请求分配资源，最终可能耗尽其连接表，导致无法处理正常请求。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;UDP Flood&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者向目标发送大量的 UDP 数据包，通常使用随机端口号。目标接收到这些数据包后，会尝试响应，但由于请求量过大，最终会消耗带宽和处理能力。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;ICMP Flood（Ping Flood）&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者发送大量 ICMP 回显请求（Ping），目标服务器需要处理这些请求并发送回显应答，导致其资源被耗尽。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;HTTP Flood&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者发送大量的 HTTP 请求（例如，通过伪造的浏览器请求），使得 Web 服务器无法处理正常用户的请求，导致服务中断。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;MAC Flood&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;mac-flood&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mac-flood&#34;&gt;#&lt;/a&gt; MAC Flood&lt;/h4&gt;
&lt;h5 id=&#34;交换机的-mac-地址表工作原理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#交换机的-mac-地址表工作原理&#34;&gt;#&lt;/a&gt; 交换机的 MAC 地址表工作原理&lt;/h5&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;学习阶段&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;当交换机接收到一个数据帧时，它会查看源 MAC 地址，并将该地址与接收该帧的端口记录到 MAC 地址表中。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;转发阶段&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;如果交换机的 MAC 地址表中有目标 MAC 地址，它会将数据帧转发到对应的端口；如果没有，就会进行广播。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;老化机制&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;为了保持 MAC 地址表的有效性，交换机会定期检查并删除长时间未使用的 MAC 地址。这称为老化（aging）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h6 id=&#34;攻击方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#攻击方式&#34;&gt;#&lt;/a&gt; 攻击方式:&lt;/h6&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;占满 MAC 地址表&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者通过工具（如  &lt;code&gt;macof&lt;/code&gt; ）发送大量伪造的以太网帧，每个帧使用不同的源 MAC 地址。这样做的目的是快速填满交换机的 MAC 地址表。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;MAC 地址表溢出&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;当 MAC 地址表被填满后，交换机将无法再学习新的 MAC 地址。此时，交换机会将收到的数据帧广播到所有端口，而不是根据 MAC 地址转发。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;导致广播风暴&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;由于广播数据帧会发送到所有端口，网络中流量会显著增加，导致拥塞和延迟。合法用户的流量可能被干扰，网络性能下降。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;影响网络安全&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;攻击者可以利用广播的特性监听通过网络传输的所有数据，进一步实施其他攻击，比如嗅探数据包。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h5 id=&#34;攻击方式-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#攻击方式-2&#34;&gt;#&lt;/a&gt; 攻击方式&lt;/h5&gt;
&lt;p&gt;macof 进行攻击 ，一般都是在打的都是局域网交换机。 主要是他会模拟多台设备访问 mac 表。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;无线接入点（AP）&lt;/strong&gt;：无线网络中的接入点负责处理设备之间的流量。尽管没有物理交换机，但 AP 仍然会维护一个 MAC 地址表，用于确定数据包应该发送到哪个设备。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;MAC 泛洪攻击&lt;/strong&gt;：即使在无线网络中，使用  &lt;code&gt;macof&lt;/code&gt;  等工具进行 MAC 泛洪攻击仍然可以导致 AP 的 MAC 地址表溢出，从而使得流量被广播到所有连接的设备。这会影响到所有连接在同一热点上的设备。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h5 id=&#34;mac防御&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mac防御&#34;&gt;#&lt;/a&gt; mac 防御&lt;/h5&gt;
&lt;p&gt;是的，使用静态 MAC 转发表可以有效减少广播的发生。在静态 MAC 转发表中，交换机只知道那些手动配置的 MAC 地址，因此不会因为接收到未知的 MAC 地址而发送广播。&lt;/p&gt;
&lt;h6 id=&#34;具体影响如下&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#具体影响如下&#34;&gt;#&lt;/a&gt; 具体影响如下：&lt;/h6&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;减少广播域的大小&lt;/strong&gt;：由于交换机只处理已知的静态 MAC 地址，任何未知地址的流量不会引发广播，从而减少了广播风暴的可能性。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;提高网络性能&lt;/strong&gt;：减少广播流量有助于提高网络的整体性能和响应速度，因为交换机不再需要处理大量无效的广播包。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;增强安全性&lt;/strong&gt;：静态配置的 MAC 地址表可以防止攻击者通过伪造 MAC 地址进行网络攻击，从而降低了网络被滥用的风险&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;防守策略&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#防守策略&#34;&gt;#&lt;/a&gt; 防守策略&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;流量监测与分析&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用流量监测工具检测异常流量模式，及时识别攻击行为。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;流量限制&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;对每个 IP 地址的请求数量进行限制，减少恶意请求的影响。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;防火墙与入侵检测系统（IDS）&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;部署防火墙和 IDS，可以识别并阻止恶意流量。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;负载均衡&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用负载均衡技术分散流量，将请求分散到多个服务器上，降低单个服务器的压力。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;黑名单 / 白名单策略&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;根据流量来源设置黑名单或白名单，限制不明或可疑的 IP 地址&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;mac泛洪攻击实验&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mac泛洪攻击实验&#34;&gt;#&lt;/a&gt; MAC 泛洪攻击实验&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;建立网络拓扑&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104202636.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;简单解释一下，我们利用云开了两个端口，我用的桥接网卡将 ip 设置为 192.168.234.22&lt;br /&gt;
 加入到了我们局域网中&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104202726.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104202926.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;由于我们需要 mac 泛洪攻击就是，填充 mac 表因此先清空 mac 表。&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;sy &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;display mac-address&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;undo    mac-address&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104203134.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;开始泛洪攻击&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;占用资源，使得局域网内部通信变慢&lt;/li&gt;
&lt;li&gt;嗅探局域网内部信息&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;因此我们是使用刚才的 client 和 server 进行模拟正常用户正常流量通过，之后我们利用泛洪攻击针对于数据进行嗅探。&lt;br /&gt;
在 Kali Linux 中安装  &lt;code&gt;macof&lt;/code&gt; （通常作为  &lt;code&gt;dsniff&lt;/code&gt;  套件的一部分）&lt;/p&gt;
&lt;h5 id=&#34;ps-mac泛洪只能在局域网&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ps-mac泛洪只能在局域网&#34;&gt;#&lt;/a&gt; PS mac 泛洪只能在局域网&lt;/h5&gt;
&lt;p&gt;网络隔离：路由器设计的目的就是将不同的网络隔离开来，广播帧不会跨越路由器。因此，虽然你可以通过路由器访问另一个局域网，但 MAC 地址泛洪攻击需要在同一个局域网内部进行，而不是跨网络。&lt;/p&gt;
&lt;p&gt;数据链路层的限制：在数据链路层，MAC 地址是局域网内使用的。即使你通过路由器连接到另一个局域网，你的 MAC 帧依然是基于你的本地网络环境发送的，不会影响目标局域网的交换机。&lt;/p&gt;
&lt;p&gt;防火墙和安全机制：现代网络通常会配置防火墙和其他安全机制来防止未经授权的访问。这些机制会限制对内部网络的访问，进一步阻碍了通过路由器进行 MAC 泛洪攻击的可能性。&lt;/p&gt;
&lt;h5 id=&#34;ftp文件传输&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ftp文件传输&#34;&gt;#&lt;/a&gt; ftp 文件传输&lt;/h5&gt;
&lt;p&gt;模拟正常用户文件传输&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104205736.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104212139.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20241104212150.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;

 &lt;h6 id=&#34;子域名泛解析的成因&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#子域名泛解析的成因&#34;&gt;#&lt;/a&gt; 子域名泛解析的成因&lt;/h6&gt;
&lt;p&gt;在子域名解析中，每个子域名都会解析为一个特定的 IP 地址。只有被设置解析，用户才能正常进行访问。&lt;br /&gt;
  一旦用户输入错误的子域名，就会造成无法访问。&lt;br /&gt;
  在网站运营中，域名持有者为了避免因为错误输入，而造成用户流失，就会使用泛域名解析。&lt;br /&gt;
  泛域名解析是一种特殊的域名解析方式。它使用通配符形式，设置域名解析。&lt;br /&gt;
  它可以将没有明确设置的子域名一律解析到一个 IP 地址上。这样，即使用户输入错误的子域名，也可以访问到域名持有者指定的 IP 地址。&lt;br /&gt;
  但是信息收集中，这会造成请求的所有子域名都能访问的假象，从而收集到一堆无效的子域名。&lt;/p&gt;
&lt;p&gt;其实最主要还是因为，在子域名收集中怕在进行子域名收集时候找到很多错误的子域名&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;泛域名解析是：*.域名解析到同一IP&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;域名解析是：子域名.域名解析到同一IP&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;但我觉得一般是三级域名，&lt;a href=&#34;http://xn--shop-kf5f9fozj0c72ikszkggyuigv3a1zbn94h4x6djxebqm3ibs5h.example.com&#34;&gt;对应的如果说有这个资产那么你输入 shop.example.com&lt;/a&gt; 可能就会解析对应 ip 但是他也有泛解析，你输入一个复杂的泛解析他也会解析识别 。&lt;/p&gt;
&lt;h4 id=&#34;判断是否是泛解析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#判断是否是泛解析&#34;&gt;#&lt;/a&gt; 判断是否是泛解析&lt;/h4&gt;
&lt;p&gt;这里以淘宝和百度为例子:ping 一个绝对随机不可能存在的域名，他解析了，那么说明他大概率使用了泛解析&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://img2022.cnblogs.com/blog/1090320/202203/1090320-20220303113103812-1435020700.png&#34; alt=&#34;&#34; /&gt;针对百度，我们可以直接使用 layer 子域名挖掘机等子域名爆破工具，而针对淘宝的资产，我们不能使用 layer 子域名挖掘机等常规工具&lt;/p&gt;
&lt;h4 id=&#34;解决方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#解决方式&#34;&gt;#&lt;/a&gt; 解决方式&lt;/h4&gt;
&lt;p&gt;1、先获取一个肯定不存在的子域名，并解析其获取其 ip，记为 ip-A。然后爆破获取到的域名均进行解析获取 ip，记为 ip-B，与 ip-A 进行对比，不一致则可判定为真实存在的子域名。&lt;/p&gt;
&lt;p&gt;2、比对响应 TTL 值，比对过程同上，不一致则为真实存在的子域名。&lt;/p&gt;
&lt;p&gt;这种方式 可以完美的解决对应的收集到的垃圾域名问题。通过对比一定解析错误的 ip 或者 ttl 值我们可以看到哪些域名是真的，哪些域名是因为泛解析是假的。&lt;/p&gt;

 &lt;h4 id=&#34;misc&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#misc&#34;&gt;#&lt;/a&gt; misc&lt;/h4&gt;
&lt;p&gt;具体 flag 放入 github 中&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/k1t0111/Ctf-AWD/tree/k1t0111-wdflag2024-1&#34;&gt;https://github.com/k1t0111/Ctf-AWD/tree/k1t0111-wdflag2024-1&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;web&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web&#34;&gt;#&lt;/a&gt; web&lt;/h4&gt;
&lt;p&gt;可以看到首先随便一个登陆页面进去，进到飞机管理清单后台。然后发现了两处功能点。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;首先写一个清单，作为飞机起飞列表&lt;/li&gt;
&lt;li&gt;提交清单&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;em&gt;&lt;strong&gt;思路:&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;清单提交可以触发 xss&lt;/li&gt;
&lt;li&gt;使用前端 xss 代码提交给 boss 然后在 boss 地方触发&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;figcaption data-lang=&#34;HTML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token script&#34;&gt;&lt;span class=&#34;token language-javascript&#34;&gt;&lt;span class=&#34;token function&#34;&gt;fetch&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;flag&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;then&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;response&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt;response&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;text&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;then&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token parameter&#34;&gt;data&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token function&#34;&gt;fetch&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;/content/a93770ea93dc1f6a2b9d917b62d29db4&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token literal-property property&#34;&gt;method&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;POST&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token literal-property property&#34;&gt;body&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;content=abc&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;encodeURLComponent&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;data&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token literal-property property&#34;&gt;headers&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token string-property property&#34;&gt;&#39;Content-Type&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;application/x-www-form-urlencoded&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;	&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;主体大意就是，因为尝试了 boss 是无法出网的因此我们使用 js，使用 boss 的 cookie 去访问 flag。&lt;br /&gt;
然后把内容放在 data 中。同时继续访问另外一个文件将 data 内容作为 post 参数传递进去。然后修改 hash 文件的内容。我们再去访问 hash 就可以直接访问到 flag。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;总结&lt;/strong&gt;最主要还是因为不出网络，因此我们拿不到 cookie，因此想到了 js 功能，让 boss 自己去访问 flag 带出 flag&lt;/p&gt;

 &lt;h4 id=&#34;web&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web&#34;&gt;#&lt;/a&gt; web&lt;/h4&gt;
&lt;h5 id=&#34;签到&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#签到&#34;&gt;#&lt;/a&gt; 签到&lt;/h5&gt;
&lt;p&gt;略&lt;/p&gt;
&lt;h5 id=&#34;web1&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web1&#34;&gt;#&lt;/a&gt; web1&lt;/h5&gt;
&lt;p&gt;上传 php 一句话木马&lt;/p&gt;
&lt;h5 id=&#34;web2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web2&#34;&gt;#&lt;/a&gt; web2&lt;/h5&gt;
&lt;p&gt;sql 注入注入点在消息通知中，找到 id 参数。数字型注入直接找到 order by 4&lt;br /&gt;
 直接报错注入。&lt;/p&gt;
&lt;h5 id=&#34;web3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web3&#34;&gt;#&lt;/a&gt; web3&lt;/h5&gt;
&lt;p&gt;web3 是唯一一道有难度的题目，可以看到一开始给了一个页面。显示的是一个系统代码被修改了。我们扫描目录扫描到 wwwroot.zip。直接把系统源码下载下来。&lt;/p&gt;
&lt;p&gt;其实我们仔细分析一下这个提示，他就说因为被篡改了所以说网站紧急关闭。同时把系统代码备份了。此时我们考虑如果说我们没有交互界面我们无法进行操作，那么肯定是有一些站点没有关闭。&lt;br /&gt;
遍历所有文件，发现只有一个文件返回了一个字符串，直接审计这个文件。&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;describedssTest.php&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token php language-php&#34;&gt;&lt;span class=&#34;token delimiter important&#34;&gt;&amp;lt;?php&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;error_reporting&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;Content-type: text/html; charset=utf-8&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$p8&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;3b7430adaed18facca7b799229138b7b&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$a8&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;TURNeU9UWTBOelUwTmprd05UUTVOR0ZLV1ZwdU9XSkZORmh2WnpoS1RrNW1jRTFrTkdjOVBRPT0=&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$d8&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;TURNeU9UWTBOelUwTmprd05UUTVOR012V1c5cVJXNXBkWEJyZDFsemJsQlpNMmRITjNaYWVFVnFPVWRqVnpoWlUyNXZNbmhDU21jd2RHTkxRazF2U1hvMU9FNUNWM2RNUjFWYVJuVnBiV3czUlVwUldFMTFhakp2VjJKS1NIVlJUMU5UYjNoSWExUk5hMlZXY21OdlRuaHVRMjlsVkV4aEwzbGpQUT09&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$v8&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;0329647546905494&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$D&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$K&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$cipher&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;aes-128-cbc&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$encrypted&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;openssl_encrypt&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$D&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$cipher&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$K&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$GLOBALS&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;v8&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;base64_encode&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$GLOBALS&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;v8&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;.&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$encrypted&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;base64_encode&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$result&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$D&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$K&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&